INSERT OR REPLACE INTO quality_profiles (name, description, upgrades_allowed, minimum_custom_format_score, upgrade_until_score, upgrade_score_increment) VALUES ('Alex_C.T - 1080p-2160p Plex Movies', 'Primary movie profile for space-conscious Plex libraries. It prioritizes feature-rich 1080p HDR/DoVi with 5.1+ audio first, then compact 2160p HDR/DoVi with 5.1+ audio, then less feature-rich fallbacks. Spanish-friendly, Latino, MULTI, and EN+ES releases are strongly favored. Target rip quality: 8.5/10.', 1, 0, 13000, 125);
